var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"특별 군사 고문으로 자네들을 등록해 놨네.","JPN":"特別軍事顧問に君たちを登録しておいた。","ENG":"I've registered you all as special advisors for the army.","TWN":"我已經將你們登記為特別軍事顧問。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"혹시 모를 사태에 대비해 관련 인원들은 모두 외곽으로 빼놨으니 안심해도 될 거야.","JPN":"予期せぬ事態に備えて、職員は全員外部に回したから安心していいだろう。","ENG":"And all relevant personnel have been moved outside in case anything goes wrong.","TWN":"以防萬一，我也已經將人員都調到外面，你們放心吧。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우리가 이곳에서 할 일은 간단해.","JPN":"私たちがここでやることはいたってシンプル。","ENG":"Our job here is simple.","TWN":"我們要做的事很簡單。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"전파를 찾고, 그 근원지를 찾고, 유포자를 찾는다.","JPN":"電波を探し、その根源地を探り、発信者を探す。","ENG":"Find the radio signal, find the source, then find the distributor.","TWN":"就是找到電波，找到源頭，找到散布者。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"간단하지? 바보라도 알 수 있는 부분이라고.","JPN":"簡単でしょ？　バカでもわかることだよ。","ENG":"Simple as that. Even an idiot would understand.","TWN":"很簡單吧？笨蛋也聽得懂吧？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그리고 나는 혹시 남아있을 침식체를 박살 낸다. 이해했어.","JPN":"そして俺は残っているかもしれない侵食体をぶっ倒す。理解した。","ENG":"Oh, and if I see any C.O.s, I crush them. Got it.","TWN":"然後我負責清除可能殘留在這裡的侵蝕體，收到。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 간단한 작전을 이해 못하는 근육 뇌가 있다는 걸 깜빡했네.","JPN":"こんな単純な作戦を理解できない脳みそ筋肉がいるということを忘れてた。","ENG":"I almost forgot we have a musclebrain who can't even get a simple mission through his thick skull.","TWN":"我差點忘記這裡有個頭腦簡單四肢發達的傢伙。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 몸에서 방출되는 전기는 전파 수신에 방해가 돼. 그러니까 아무 짓도 하지 마.","JPN":"その体から放出される電気は電波受信の邪魔になるの。だから何もしないで。","ENG":"The electricity pulse you emit will only interfere with the signal. So don't do anything.","TWN":"你體內釋放的電氣會妨礙電波接收，拜託你什麼也別做。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"만담은 재밌지만, 잠깐 조용히 해주겠어?","JPN":"二人の漫才は面白いんだが、ちょっと静かにしてくれるか？","ENG":"Chit chat's fun and all, but could you pipe down?","TWN":"脫口秀是很精彩，但可以稍微安靜一下嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그때 전파를 받았던 주파수를 찾는 중이니까.","JPN":"あの時電波を受けた周波数を探しているんだ。","ENG":"I'm trying to find the frequency of the signal.","TWN":"我正在找那時候接收到的電波頻率。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"동영상은커녕 사람 소리도 안 들리는데.","JPN":"映像どころか人の声も聞こえないね。","ENG":"I can't find any traces of a video, let alone a sound.","TWN":"什麼影片，根本連個人影都沒看到。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말 여기가 맞는 거야, 아저씨?","JPN":"おじさん、本当にここで合っているの？","ENG":"Are you sure this is the right place, Mr. Mason?","TWN":"大叔，你確定是這裡嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이대로 간다면 우린 아저씨가 사기꾼이 됐다고 여길 수밖에 없어.","JPN":"このままだとおじさんは詐欺師扱いになるよ。","ENG":"At this rate, we have no choice but to call you a scammer.","TWN":"再找不到的話，我們只能認定你是詐騙集團的囉。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"신뢰야말로 용병의 생명줄이야.","JPN":"信頼こそが傭兵の命だ。","ENG":"Credibility is a mercenary's lifeline.","TWN":"傭兵把誠信看得跟性命一樣重要。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"거짓 정보로 군을 자극할 만큼 나는 멍청하지도 않고 말이지.","JPN":"偽りの情報で軍を刺激するほどバカでもない。","ENG":"I'm not stupid enough to annoy the military with false intel.","TWN":"我還沒笨到拿假消息去刺激軍人。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 젠장. 기계가 말을 듣지 않아.","JPN":"チクショウ。機械が言うことを聞かない。","ENG":"Dammit. The device isn't working.","TWN":"該死，機器不聽使喚。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"더한 침식 환경에서도 견딜 수 있는 녀석인데……","JPN":"ここより酷い侵食環境でも使えるやつなのに……","ENG":"It was supposed to endure Corruption environments far worse than this one...","TWN":"明明在更強烈的侵蝕環境中也沒問題的……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"전파 신호는 잡았지만, 기계가 갑자기 먹통이 됐어.","JPN":"電波信号は捕まえたけど、機械がいきなり動かなくなった。","ENG":"I got a signal, but the device froze up.","TWN":"是有抓到電波訊號，但機器突然故障。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"후후. 기계가 말을 듣지 않을 땐, 아주 확실한 방법이 있지.","JPN":"ふふ。機械が言うことを聞かない時は、確実な方法がある。","ENG":"Hah hah, I know a way to fix devices when they don't work.","TWN":"呵呵，機器不聽話時，這是最好的辦法。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저기, 설마 내가 생각하는 그 방법은 아니지?","JPN":"ねぇ、まさかあの方法じゃないよね？","ENG":"Wait... You're not thinking of doing what I'm thinking, are you?","TWN":"喂，你說的辦法該不會是我想的那個吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"네가 어떤 생각을 하는지 모르지만…….","JPN":"シルビアが何を考えているのかはわからないが……","ENG":"I don't know what you're thinking, but...","TWN":"我怎麼知道你在想什麼……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};